t.script:
//
(function(){
document.addEventListener('DOMContentLoaded', function(){

    var BASE_URL      = '/my/employee/certification';
    var STORAGE_KEY   = 'ess_cert_pending';
    var csrfToken     = '';
    var pendingChanges = [];  /* in-memory for FormData (files) */
    var tempIdCounter  = -1;

    var csrfEl = document.querySelector('input[name="csrf_token"]');
    if (csrfEl) csrfToken = csrfEl.value;

    /* ── Load staged changes from localStorage on page load ── */
    function loadFromStorage() {
        try {
            var stored = JSON.parse(localStorage.getItem(STORAGE_KEY) || 'null');
            if (!stored || !stored.changes || stored.changes.length === 0) return;
            stored.changes.forEach(function(c) {
                if (c.type === 'delete') {
                    pendingChanges.push(c);
                    var r = getRow(c.rowId);
                    if (r) {
                        r.classList.add('cert-staged-delete');
                        addRowBadge(r, 'delete');
                        r.querySelector('.cert-action-col').innerHTML =
                            '<button type="button" class="btn btn-sm btn-outline-secondary ess-btn-undo-delete" data-id="'+c.rowId+'" title="Undo"><i class="fa fa-undo me-1"></i>Undo</button>';
                        bindUndoOnRow(r);
                    }
                } else if (c.type === 'add' && c.payload) {
                    pendingChanges.push(c);
                    var tbody = document.getElementById('certTableBody');
                    var emptyRow = document.getElementById('certEmptyRow');
                    if (emptyRow) emptyRow.remove();
                    var tr = document.createElement('tr');
                    tr.setAttribute('data-id', c.rowId);
                    tr.setAttribute('data-skill-name', c.payload.skillName || '');
                    tr.setAttribute('data-from', c.payload.validFrom || '');
                    tr.setAttribute('data-to',   c.payload.validTo   || '');
                    tr.classList.add('cert-staged-add');
                    tr.innerHTML =
                        '<td style="padding:13px 18px;vertical-align:middle;font-size:14px;" class="col-skill-name">' + escHtml(c.payload.skillName) + '<span class="cert-staged-badge badge-staged-add">New</span></td>' +
                        '<td style="padding:13px 18px;vertical-align:middle;" class="col-attachments"><span class="text-muted" style="font-size:13px;">—</span></td>' +
                        '<td style="padding:13px 18px;vertical-align:middle;font-size:14px;" class="col-from">' + (c.payload.validFrom ? formatDate(c.payload.validFrom) : '—') + '</td>' +
                        '<td style="padding:13px 18px;vertical-align:middle;font-size:14px;" class="col-to">' + (c.payload.validTo ? formatDate(c.payload.validTo) : '<span class="text-muted">Indefinite</span>') + '</td>' +
                        '<td class="cert-action-col" style="display:none;padding:13px 18px;vertical-align:middle;text-align:right;">' +
                        '<button type="button" class="btn btn-sm btn-outline-danger ess-btn-delete-cert" data-id="' + c.rowId + '"><i class="fa fa-trash"></i></button></td>';
                    if (tbody) { tbody.appendChild(tr); bindDeleteOnRow(tr); }
                } else if (c.type === 'edit' && c.rowId && c.payload) {
                    pendingChanges.push(c);
                    var r = getRow(c.rowId);
                    if (r) {
                        r.setAttribute('data-from', c.payload.validFrom || '');
                        r.setAttribute('data-to',   c.payload.validTo   || '');
                        r.querySelector('.col-from').textContent = c.payload.validFrom ? formatDate(c.payload.validFrom) : '—';
                        r.querySelector('.col-to').innerHTML = c.payload.validTo ? formatDate(c.payload.validTo) : '<span class="text-muted">Indefinite</span>';
                        r.classList.add('cert-staged-edit');
                        addRowBadge(r, 'edit');
                    }
                }
            });
            /* Auto-enter edit mode if we restored anything */
            if (pendingChanges.length > 0) {
                enableEditMode();
            }
        } catch(e) {}
    }

    /* ── Save current pending changes to localStorage ── */
    /* Files (FormData) cannot be stored; add/edit without attachment + delete are stored */
    function saveToStorage() {
        var toStore = pendingChanges.filter(function(c) {
            return c.type === 'delete' ||
                   (c.type === 'edit'  && c.displayData) ||
                   (c.type === 'add'   && c.displayData);
        }).map(function(c) {
            if (c.type === 'delete') {
                return { type: 'delete', rowId: c.rowId, payload: {} };
            } else if (c.type === 'add') {
                return { type: 'add', rowId: c.rowId, payload: {
                    skillId:   (c.displayData.skillId   || ''),
                    skillName: (c.displayData.skillName || ''),
                    validFrom: (c.displayData.validFrom || ''),
                    validTo:   (c.displayData.validTo   || ''),
                }};
            } else { /* edit */
                return { type: 'edit', rowId: c.rowId, payload: {
                    validFrom: (c.displayData.validFrom || ''),
                    validTo:   (c.displayData.validTo   || ''),
                }};
            }
        });
        try {
            if (toStore.length > 0) {
                localStorage.setItem(STORAGE_KEY, JSON.stringify({ changes: toStore }));
            } else {
                localStorage.removeItem(STORAGE_KEY);
            }
        } catch(e) {}
    }

    /* ── Save before navigating to another portal tab ── */
    window.essSaveBeforeNav = function() {
        saveToStorage();
    };

    window.essHasUnsavedChanges = function() {
        return pendingChanges.length > 0;
    };

    /* beforeunload removed — base template intercepts tab clicks and
       calls essSaveBeforeNav() before navigating, so no dialog appears. */

    /* Expose clear function for global bar discard */
    window.essClearLocalStage = function() {
        pendingChanges = [];
        localStorage.removeItem(STORAGE_KEY);
        /* Remove staged visual indicators */
        document.querySelectorAll('#certTableBody tr.cert-staged-add').forEach(function(r){ r.remove(); });
        document.querySelectorAll('#certTableBody tr.cert-staged-edit, #certTableBody tr.cert-staged-delete').forEach(function(r){
            r.classList.remove('cert-staged-edit', 'cert-staged-delete');
            var badge = r.querySelector('.cert-staged-badge'); if(badge) badge.remove();
        });
        disableEditMode();
    };

    /* ── Fix last-updated timezone ── */
    (function(){
        var el = document.getElementById('certLastUpdated');
        if (!el) return;
        var raw = (el.textContent||'').trim().replace(/\u00a0/g,' ');
        if (!raw || raw === 'Never') return;
        try {
            var m = raw.match(/(\d{1,2})\s+(\w+),?\s+(\d{4})\s+at\s+(\d{1,2}):(\d{2})\s*(AM|PM)/i);
            if (!m) return;
            var months={jan:0,feb:1,mar:2,apr:3,may:4,jun:5,jul:6,aug:7,sep:8,oct:9,nov:10,dec:11};
            var hr=parseInt(m[4],10), isPM=m[6].toUpperCase()==='PM';
            if(isPM&&hr<12)hr+=12; if(!isPM&&hr===12)hr=0;
            var dt=new Date(Date.UTC(parseInt(m[3],10),months[m[2].toLowerCase().substring(0,3)],parseInt(m[1],10),hr,parseInt(m[5],10)));
            if(!isNaN(dt.getTime()))
                el.textContent=dt.toLocaleString(undefined,{day:'2-digit',month:'short',year:'numeric',hour:'2-digit',minute:'2-digit',hour12:true});
        } catch(e){}
    })();

    function showMsg(text, type) {
        var c=document.getElementById('certMessageContainer');
        var s=document.getElementById('certSuccessMessage');
        var er=document.getElementById('certErrorMessage');
        s.style.display='none'; s.classList.remove('show');
        er.style.display='none'; er.classList.remove('show');
        if(type==='success'||type==='info'){
            document.getElementById('certSuccessText').textContent=text;
            s.style.display='block'; s.classList.add('show');
        } else {
            document.getElementById('certErrorText').textContent=text;
            er.style.display='block'; er.classList.add('show');
        }
        c.style.display='block';
        c.scrollIntoView({behavior:'smooth'});
        setTimeout(function(){s.classList.remove('show');er.classList.remove('show');},6000);
    }

    function formatDate(val){
        if(!val) return '';
        var p=val.split('-'); if(p.length!==3) return val;
        var months=['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
        return parseInt(p[2],10)+' '+months[parseInt(p[1],10)-1]+' '+p[0];
    }

    function getRow(rowId){ return document.querySelector('#certTableBody tr[data-id="'+rowId+'"]'); }
    function clearRowBadge(row){ var b=row.querySelector('.cert-staged-badge'); if(b) b.remove(); }

    function addRowBadge(row,type){
        clearRowBadge(row);
        var labels={add:'New',edit:'Edited',delete:'To Delete'};
        var classes={add:'badge-staged-add',edit:'badge-staged-edit',delete:'badge-staged-delete'};
        var span=document.createElement('span');
        span.className='cert-staged-badge '+classes[type];
        span.textContent=labels[type];
        row.querySelector('.col-skill-name').appendChild(span);
    }

    function escHtml(str){ return String(str||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
    function openModal(id){document.getElementById(id).style.display='flex';}
    function closeModal(id){document.getElementById(id).style.display='none';}

    /* ── Lock edit button if pending HR review ── */
    (function lockIfPending(){
        var hasPending = document.getElementById('pendingCertCard');
        var editBtn    = document.getElementById('certEditBtn');
        if (hasPending && editBtn) {
            editBtn.disabled = true;
            editBtn.innerHTML = '<i class="fa fa-lock me-1"></i>Pending HR Review';
            editBtn.classList.remove('btn-outline-primary');
            editBtn.classList.add('btn-warning');
            editBtn.style.cursor = 'not-allowed';
        }
    })();

    /* ── File labels ── */
    document.getElementById('addFileInput').addEventListener('change',function(){
        var l=document.getElementById('addAttachLabel');
        l.textContent=this.files[0]?this.files[0].name:'Nothing attached.';
        l.style.color=this.files[0]?'#333':'';
    });
    document.getElementById('editFileInput').addEventListener('change',function(){
        var l=document.getElementById('editAttachLabel');
        l.textContent=this.files[0]?this.files[0].name:'Choose a file to add or replace.';
        l.style.color=this.files[0]?'#333':'';
    });

    /* ── ADD modal ── */
    document.getElementById('openAddModal').addEventListener('click',function(){
        document.getElementById('addCertForm').reset();
        document.getElementById('addAttachLabel').textContent='Nothing attached.';
        document.getElementById('addAttachLabel').style.color='';
        openModal('addModal');
    });
    document.getElementById('closeAddModal').addEventListener('click',function(){closeModal('addModal');});
    document.getElementById('closeAddModal2').addEventListener('click',function(){closeModal('addModal');});
    document.getElementById('addModal').addEventListener('click',function(e){if(e.target===this)closeModal('addModal');});

    document.getElementById('addCertForm').addEventListener('submit',function(e){
        e.preventDefault(); e.stopPropagation();
        var select=document.getElementById('addSkillSelect');
        var skillId=select.value;
        var skillName=select.options[select.selectedIndex]?select.options[select.selectedIndex].text:'';
        var validFrom=document.getElementById('addValidFrom').value;
        var validTo=document.getElementById('addValidTo').value;
        var fileInput=document.getElementById('addFileInput');
        var fileName=fileInput.files[0]?fileInput.files[0].name:'';
        if(!skillId){showMsg('Please select a Certificate Name.','error');return;}
        var fd=new FormData(this); fd.append('action','add_certification');
        var tempId=tempIdCounter--;
        /* FormData cannot be stored in localStorage — keep in memory */
        pendingChanges.push({type:'add',rowId:tempId,formData:fd,displayData:{skillId:skillId,skillName:skillName,validFrom:validFrom,validTo:validTo,fileName:fileName}});
        var tbody=document.getElementById('certTableBody');
        var emptyRow=document.getElementById('certEmptyRow'); if(emptyRow) emptyRow.remove();
        var tr=document.createElement('tr');
        tr.setAttribute('data-id',tempId); tr.setAttribute('data-skill-name',skillName);
        tr.setAttribute('data-from',validFrom); tr.setAttribute('data-to',validTo);
        tr.classList.add('cert-staged-add');
        tr.innerHTML=
            '<td style="padding:13px 18px;vertical-align:middle;font-size:14px;" class="col-skill-name">'+escHtml(skillName)+'<span class="cert-staged-badge badge-staged-add">New</span></td>'+
            '<td style="padding:13px 18px;vertical-align:middle;" class="col-attachments">'+(fileName?'<span style="color:#555;font-size:13px;"><i class="fa fa-file-o me-1"></i>'+escHtml(fileName)+'</span>':'<span class="text-muted">—</span>')+'</td>'+
            '<td style="padding:13px 18px;vertical-align:middle;font-size:14px;" class="col-from">'+(validFrom?formatDate(validFrom):'—')+'</td>'+
            '<td style="padding:13px 18px;vertical-align:middle;font-size:14px;" class="col-to">'+(validTo?formatDate(validTo):'<span class="text-muted">Indefinite</span>')+'</td>'+
            '<td class="cert-action-col" style="padding:13px 18px;vertical-align:middle;text-align:right;white-space:nowrap;">'+
                '<button type="button" class="btn btn-sm btn-outline-danger ess-btn-delete-cert" data-id="'+tempId+'"><i class="fa fa-trash"></i></button>'+
            '</td>';
        tbody.appendChild(tr);
        bindDeleteOnRow(tr);
        saveToStorage();
        closeModal('addModal');
        showMsg('Certification staged. Use the Submit All bar at the bottom to send to HR.','info');
    });

    /* ── EDIT modal ── */
    function bindEditButtons(){
        document.querySelectorAll('.ess-btn-edit-cert').forEach(function(btn){
            btn.addEventListener('click',function(){
                var rowId=this.dataset.id; var row=getRow(rowId); if(!row) return;
                document.getElementById('editSkillRecordId').value=rowId;
                document.getElementById('editSkillName').value=row.dataset.skillName||'';
                document.getElementById('editValidFrom').value=row.dataset.from||'';
                document.getElementById('editValidTo').value=row.dataset.to||'';
                document.getElementById('editAttachLabel').textContent='Choose a file to add or replace.';
                document.getElementById('editAttachLabel').style.color='';
                document.getElementById('editFileInput').value='';
                openModal('editModal');
            });
        });
    }
    bindEditButtons();
    document.getElementById('closeEditModal').addEventListener('click',function(){closeModal('editModal');});
    document.getElementById('closeEditModal2').addEventListener('click',function(){closeModal('editModal');});
    document.getElementById('editModal').addEventListener('click',function(e){if(e.target===this)closeModal('editModal');});

    document.getElementById('editCertForm').addEventListener('submit',function(e){
        e.preventDefault(); e.stopPropagation();
        var rowId=document.getElementById('editSkillRecordId').value;
        var validFrom=document.getElementById('editValidFrom').value;
        var validTo=document.getElementById('editValidTo').value;
        var fileInput=document.getElementById('editFileInput');
        var fileName=fileInput.files[0]?fileInput.files[0].name:'';
        var fd=new FormData(this); fd.append('action','edit_certification');
        pendingChanges=pendingChanges.filter(function(c){return !(c.rowId==rowId&&c.type==='edit');});
        pendingChanges.push({type:'edit',rowId:rowId,formData:fd,displayData:{validFrom:validFrom,validTo:validTo,fileName:fileName}});
        var row=getRow(rowId);
        if(row){
            row.setAttribute('data-from',validFrom); row.setAttribute('data-to',validTo);
            row.querySelector('.col-from').textContent=validFrom?formatDate(validFrom):'—';
            row.querySelector('.col-to').innerHTML=validTo?formatDate(validTo):'<span class="text-muted">Indefinite</span>';
            if(fileName) row.querySelector('.col-attachments').innerHTML='<span style="color:#555;font-size:13px;"><i class="fa fa-file-o me-1"></i>'+escHtml(fileName)+' <small class="text-muted">(pending)</small></span>';
            if(!row.classList.contains('cert-staged-add')){row.classList.add('cert-staged-edit');addRowBadge(row,'edit');}
        }
        saveToStorage();
        closeModal('editModal');
        showMsg('Edit staged. Use the Submit All bar at the bottom.','info');
    });

    /* ── DELETE staging ── */
    function bindDeleteOnRow(row){
        var btn=row.querySelector('.ess-btn-delete-cert'); if(!btn) return;
        btn.addEventListener('click',function(){
            var rowId=this.dataset.id; var isTemp=parseInt(rowId,10)<0;
            if(!confirm('Remove this certification?')) return;
            if(isTemp){
                pendingChanges=pendingChanges.filter(function(c){return c.rowId!=rowId;});
                var r=getRow(rowId); if(r) r.remove();
            } else {
                pendingChanges=pendingChanges.filter(function(c){return !(c.rowId==rowId&&c.type==='edit');});
                pendingChanges=pendingChanges.filter(function(c){return !(c.rowId==rowId&&c.type==='delete');});
                pendingChanges.push({type:'delete',rowId:rowId,formData:null,displayData:{}});
                var r=getRow(rowId);
                if(r){
                    r.classList.remove('cert-staged-edit'); r.classList.add('cert-staged-delete');
                    addRowBadge(r,'delete');
                    r.querySelector('.cert-action-col').innerHTML='<button type="button" class="btn btn-sm btn-outline-secondary ess-btn-undo-delete" data-id="'+rowId+'" title="Undo"><i class="fa fa-undo me-1"></i>Undo</button>';
                    bindUndoOnRow(r);
                }
            }
            saveToStorage();
        });
    }

    function bindUndoOnRow(row){
        var btn=row.querySelector('.ess-btn-undo-delete'); if(!btn) return;
        btn.addEventListener('click',function(){
            var rowId=this.dataset.id;
            pendingChanges=pendingChanges.filter(function(c){return !(c.rowId==rowId&&c.type==='delete');});
            var r=getRow(rowId);
            if(r){
                r.classList.remove('cert-staged-delete'); clearRowBadge(r);
                r.querySelector('.cert-action-col').innerHTML=
                    '<button type="button" class="btn btn-sm btn-outline-warning ess-btn-edit-cert me-1" data-id="'+rowId+'"><i class="fa fa-pencil"></i></button>'+
                    '<button type="button" class="btn btn-sm btn-outline-danger ess-btn-delete-cert" data-id="'+rowId+'"><i class="fa fa-trash"></i></button>';
                bindEditButtons(); bindDeleteOnRow(r);
            }
            saveToStorage(); showMsg('Undo successful.','info');
        });
    }

    document.querySelectorAll('#certTableBody tr[data-id]').forEach(function(row){bindDeleteOnRow(row);});

    /* ── Edit mode ── */
    function enableEditMode(){
        document.getElementById('openAddModal').style.display='inline-flex';
        document.getElementById('certActionHeader').style.display='';
        document.querySelectorAll('.cert-action-col').forEach(function(td){td.style.display='';});
        var h=document.getElementById('certEmptyHint'); if(h) h.style.display='';
        document.getElementById('certViewActions').style.display='none';
        document.getElementById('certFormActions').style.display='block';
        var certDisc2=document.getElementById('certDisclaimer'); if(certDisc2) certDisc2.checked=false;
        var certDoneBtn2=document.getElementById('certDoneBtn'); if(certDoneBtn2){ certDoneBtn2.disabled=true; certDoneBtn2.style.opacity='0.6'; }
        updateCertBadge();
    }

    function disableEditMode(){
        document.getElementById('openAddModal').style.display='none';
        document.getElementById('certActionHeader').style.display='none';
        document.querySelectorAll('.cert-action-col').forEach(function(td){td.style.display='none';});
        var h=document.getElementById('certEmptyHint'); if(h) h.style.display='none';
        document.getElementById('certViewActions').style.display='block';
        document.getElementById('certFormActions').style.display='none';
    }

    document.getElementById('certEditBtn').addEventListener('click',function(){ if(this.disabled) return; enableEditMode(); });

    document.getElementById('certCancelBtn').addEventListener('click',function(){
        if(pendingChanges.length>0){if(!confirm('Discard all certification changes?')) return;}
        pendingChanges=[]; localStorage.removeItem(STORAGE_KEY);
        disableEditMode();
        location.reload();
    });

    /* ── Disclaimer enables submit button ── */
    var certDisc = document.getElementById('certDisclaimer');
    if(certDisc){
        certDisc.addEventListener('change', function(){
            var btn=document.getElementById('certDoneBtn');
            if(btn){ btn.disabled=!this.checked; btn.style.opacity=this.checked?'1':'0.6'; }
        });
    }

    /* ── Update pending badge ── */
    function updateCertBadge(){
        var badge=document.getElementById('certPendingBadge');
        var count=document.getElementById('certPendingCount');
        if(!badge||!count) return;
        if(pendingChanges.length>0){count.textContent=pendingChanges.length;badge.style.display='block';}
        else badge.style.display='none';
    }

    /* ── Submit for HR Approval with auto-reload ── */
    var certDoneBtn = document.getElementById('certDoneBtn');
    if(certDoneBtn){
        certDoneBtn.addEventListener('click', function(){
            if(pendingChanges.length===0){disableEditMode();return;}
            var btn=this;
            btn.disabled=true;
            btn.innerHTML='<i class="fa fa-spinner fa-spin me-1"></i>Submitting...';
            if(certDisc) certDisc.disabled=true;
            document.getElementById('certCancelBtn').disabled=true;
            document.getElementById('openAddModal').style.display='none';
            document.querySelectorAll('.cert-action-col').forEach(function(td){td.style.display='none';});

            var changes=pendingChanges.slice(); var errors=[];
            function processNext(index){
                if(index>=changes.length){
                    if(errors.length>0){
                        showMsg('Some changes failed: '+errors.join('; '),'error');
                        btn.disabled=false;
                        btn.innerHTML='<i class="fa fa-paper-plane me-1"></i>Submit for HR Approval';
                        if(certDisc) certDisc.disabled=false;
                        document.getElementById('certCancelBtn').disabled=false;
                    } else {
                        /* SUCCESS: show overlay and auto-reload */
                        pendingChanges=[]; localStorage.removeItem(STORAGE_KEY);
                        var overlay=document.createElement('div');
                        overlay.style.cssText='position:fixed;inset:0;z-index:99999;background:rgba(255,255,255,0.95);display:flex;align-items:center;justify-content:center;';
                        overlay.innerHTML='<div style="text-align:center;padding:32px;background:white;border-radius:16px;box-shadow:0 8px 40px rgba(0,0,0,0.12);max-width:420px;">' +
                            '<div style="font-size:52px;margin-bottom:14px;">✅</div>' +
                            '<h4 style="color:#155724;font-weight:700;margin-bottom:10px;">Certifications Submitted!</h4>' +
                            '<p style="color:#555;margin-bottom:12px;">Your certification changes have been sent to HR for approval.</p>' +
                            '<p style="color:#888;font-size:13px;"><i class="fa fa-refresh fa-spin me-1"></i>Reloading...</p>' +
                            '<div style="height:4px;background:#e0e0e0;border-radius:4px;overflow:hidden;width:180px;margin:12px auto 0;">' +
                            '<div id="cert-prog" style="height:100%;width:0%;background:#0d6efd;border-radius:4px;transition:width 1.3s linear;"></div></div>' +
                            '</div>';
                        document.body.appendChild(overlay);
                        setTimeout(function(){ var p=document.getElementById('cert-prog'); if(p) p.style.width='100%'; }, 50);
                        setTimeout(function(){ location.reload(); }, 1500);
                    }
                    return;
                }
                var change=changes[index];
                if(change.type==='delete'){
                    var fd=new FormData(); fd.append('action','delete_certification');
                    fd.append('skill_record_id',change.rowId); fd.append('csrf_token',csrfToken);
                    fetch(BASE_URL,{method:'POST',body:fd})
                        .then(function(r){return r.json();})
                        .then(function(d){if(!d.success)errors.push('Delete: '+(d.error||'failed'));processNext(index+1);})
                        .catch(function(){errors.push('Delete: network error');processNext(index+1);});
                } else if(change.type==='add'&&change.formData){
                    fetch(BASE_URL,{method:'POST',body:change.formData})
                        .then(function(r){return r.json();})
                        .then(function(d){if(!d.success)errors.push('Add: '+(d.error||'failed'));processNext(index+1);})
                        .catch(function(){errors.push('Add: network error');processNext(index+1);});
                } else if(change.type==='edit'&&change.formData){
                    fetch(BASE_URL,{method:'POST',body:change.formData})
                        .then(function(r){return r.json();})
                        .then(function(d){if(!d.success)errors.push('Edit: '+(d.error||'failed'));processNext(index+1);})
                        .catch(function(){errors.push('Edit: network error');processNext(index+1);});
                } else { processNext(index+1); }
            }
            processNext(0);
        });
    }

    /* Load any stored deletes from previous session */
    loadFromStorage();

    /* ── Override global submit to handle FormData cert changes ── */
    /* The global bar calls submitAll which calls submitCertChange.
       For add/edit with FormData, we need to submit directly here.
       We patch the global ESS_GLOBAL after it loads. */
    document.addEventListener('ess-submit-cert', function() {
        var errors = [];
        var changes = pendingChanges.slice();

        function next(i) {
            if (i >= changes.length) {
                var ev = new CustomEvent('ess-cert-done', { detail: { errors: errors } });
                document.dispatchEvent(ev);
                return;
            }
            var c = changes[i];
            if ((c.type === 'add' || c.type === 'edit') && c.formData) {
                fetch(BASE_URL, { method: 'POST', body: c.formData })
                    .then(function(r){ return r.json(); })
                    .then(function(d){ if(!d.success) errors.push(c.type+': '+(d.error||'failed')); next(i+1); })
                    .catch(function(){ errors.push(c.type+': network error'); next(i+1); });
            } else if (c.type === 'delete') {
                var fd = new FormData();
                fd.append('action','delete_certification');
                fd.append('skill_record_id', c.rowId);
                fd.append('csrf_token', csrfToken);
                fetch(BASE_URL, { method: 'POST', body: fd })
                    .then(function(r){ return r.json(); })
                    .then(function(d){ if(!d.success) errors.push('delete: '+(d.error||'failed')); next(i+1); })
                    .catch(function(){ errors.push('delete: network error'); next(i+1); });
            } else {
                next(i+1);
            }
        }
        next(0);
    });

}); /* end DOMContentLoaded */
})();
